listRule:
// Permite que você veja qualquer usuário que tenha um cargo atribuído em QUALQUER instância.
// Isso é seguro porque o filtro inicial da requisição já limita a instância.
id = @request.auth.id || @collection.user_instance_roles.user ?= id

viewRule:
// Permite que você veja qualquer usuário que tenha um cargo atribuído em QUALQUER instância.
// Isso é seguro porque o filtro inicial da requisição já limita a instância.
id = @request.auth.id || @collection.user_instance_roles.user ?= id

// 1. Regra Original (Donos e Gestores da própria instância)
(
  @request.auth.id != "" &&
  @collection.user_instance_roles.user ?= @request.auth.id &&
  @collection.user_instance_roles.instance ?= id &&
  (@collection.user_instance_roles.role ?= "super_admin" || @collection.user_instance_roles.role ?= "gestor")
)
||
// 2. Regra Original (Super Admin Global)
(
  @request.auth.id != "" &&
  @collection.user_instance_roles.user ?= @request.auth.id &&
  @collection.user_instance_roles.role ?= "super_admin" &&
  @collection.user_instance_roles.instance.type ?= "super"
)
||
// 3. NOVA REGRA (Visibilidade via Parceria)
(
  @request.auth.id != "" &&
  // Procure nas roles do usuário atual...
  @collection.user_instance_roles.user ?= @request.auth.id &&
  // ...se ele é gestor/admin de ALGUMA instância...
  (@collection.user_instance_roles.role ?= "super_admin" || @collection.user_instance_roles.role ?= "gestor") &&
  // ...que tenha O REGISTRO ATUAL (id do parceiro) na lista de partners
  @collection.user_instance_roles.instance.partners ?~ id
)

updateRule:
@request.auth.id != "" && (
  // Verifica se é Super Admin Global
  (
    @collection.user_instance_roles:uir.user ?= @request.auth.id &&
    @collection.user_instance_roles:uir.role ?= "super_admin" &&
    @collection.user_instance_roles:uir.instance.type ?= "super"
  )
  ||
  // OU se é Super Admin desta Instância
  (
    @collection.user_instance_roles:uir.user ?= @request.auth.id &&
    @collection.user_instance_roles:uir.role ?= "super_admin" &&
    @collection.user_instance_roles:uir.instance ?= id
  )
)

